26	export const useSessionsStore = defineStore('sessions', () => {
27	  const weekSessions = ref<Session[]>([])
28	  const monthlySessions = ref<Session[]>([])
29	  const currentSession = ref<Session | null>(null)
30	  const roster = ref<any[]>([])
31	  const loading = ref(false)
32	
